#ifndef COMMON_H
#define COMMON_H

#include <cstdint>
#include <atomic>
#include <array>
#include <iostream>
using namespace std;

// Shared Memory Configuration
constexpr const char* SHM_NAME = "/market_data_shm";
constexpr size_t BUFFER_SIZE = 1024; // Must be a power of 2 for performance masking

// TCP Configuration
constexpr int TCP_PORT = 8080;
constexpr const char* TCP_IP = "127.0.0.1";

// 1. The Market Data Message Structure
// We use simple types (char array instead of std::string) so it works in Shared Memory
struct MarketMessage {
    char instrument[16];
    double bid;
    double ask;
    int64_t timestamp_ns;
};

// 2. The Lock-Free Ring Buffer
// Uses 'alignas(64)' to fit cache lines (64 bytes) and prevent "False Sharing" performance hits
struct RingBuffer {
    alignas(64) std::atomic<size_t> write_idx{0};
    alignas(64) std::atomic<size_t> read_idx{0};
    alignas(64) std::array<MarketMessage, BUFFER_SIZE> buffer;
};

#endif //COMMON_H

