#include "common.h"
#include <fmt/core.h>
#include <sys/mman.h>
#include <fcntl.h>
#include <unistd.h>
#include <chrono>
#include <thread>

int main() {
    int shm_fd = -1;
    while ((shm_fd = shm_open(SHM_NAME, O_RDONLY, 0666)) == -1) {
        std::this_thread::sleep_for(std::chrono::milliseconds(100));
    }

    auto* rb = (RingBuffer*)mmap(0, sizeof(RingBuffer), PROT_READ, MAP_SHARED, shm_fd, 0);
    size_t last_read = 0;

    fmt::print("[SHM Consumer] Connected!\n");
    while (true) {
        size_t curr_w = rb->write_idx.load(std::memory_order_acquire);
        if (last_read != curr_w) {
            auto& msg = rb->buffer[last_read];
            fmt::print("[SHM] {} BID={:.2f} ASK={:.2f}\n", msg.instrument, msg.bid, msg.ask);
            last_read = (last_read + 1) % BUFFER_SIZE;
        } else {
            std::this_thread::yield();
        }
    }
    return 0;
}

