#include "common.h"
#include <fmt/core.h>
#include <sys/mman.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <netinet/tcp.h>
#include <chrono>
#include <thread>
#include <random>
#include <cstring>

int64_t now_ns() {
    return std::chrono::duration_cast<std::chrono::nanoseconds>(
        std::chrono::system_clock::now().time_since_epoch()).count();
}

int main() {
    // 1. Setup SHM
    int shm_fd = shm_open(SHM_NAME, O_CREAT | O_RDWR, 0666);
    ftruncate(shm_fd, sizeof(RingBuffer));
    auto* rb = (RingBuffer*)mmap(0, sizeof(RingBuffer), PROT_READ | PROT_WRITE, MAP_SHARED, shm_fd, 0);

    // 2. Setup TCP (Bonus: TCP_NODELAY)
    int srv_fd = socket(AF_INET, SOCK_STREAM, 0);
    int opt = 1;
    setsockopt(srv_fd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

    sockaddr_in addr{};
    addr.sin_family = AF_INET;
    addr.sin_addr.s_addr = INADDR_ANY;
    addr.sin_port = htons(TCP_PORT);

    bind(srv_fd, (struct sockaddr*)&addr, sizeof(addr));
    listen(srv_fd, 1);

    fmt::print("[Publisher] Waiting for TCP Consumer...\n");

    // BLOCK HERE until consumer connects
    int client_fd = accept(srv_fd, nullptr, nullptr);

    // --- THIS IS THE LINE YOU WANTED ---
    fmt::print("[Publisher] TCP Consumer connected! Starting data feed.\n");

    setsockopt(client_fd, IPPROTO_TCP, TCP_NODELAY, &opt, sizeof(opt)); // Disable Nagle

    // 3. Hot Loop
    std::mt19937 rng(std::random_device{}());
    std::uniform_real_distribution<double> dist(2850.0, 2860.0);

    while (true) {
        MarketMessage msg;
        std::strncpy(msg.instrument, "RELIANCE", 16);
        msg.bid = dist(rng);
        msg.ask = msg.bid + 0.50;
        msg.timestamp_ns = now_ns();

        // Write SHM (Lock-free)
        size_t curr_w = rb->write_idx.load(std::memory_order_relaxed);
        rb->buffer[curr_w] = msg;
        rb->write_idx.store((curr_w + 1) % BUFFER_SIZE, std::memory_order_release);

        // Write TCP (JSON)
        std::string out = fmt::format(
            "{{\"instrument\":\"{}\",\"bid\":{:.2f},\"ask\":{:.2f},\"ts\":{}}}\n",
            msg.instrument, msg.bid, msg.ask, msg.timestamp_ns);
        send(client_fd, out.c_str(), out.length(), 0);

        std::this_thread::sleep_for(std::chrono::milliseconds(100));
    }
    return 0;
}

