package parkinglot.models;

public class Location {
    private final int floor;
    // A simple metric for distance from the entrance on a given floor.
    private final int distanceUnits;

    public Location(int floor, int distanceUnits) {
        this.floor = floor;
        this.distanceUnits = distanceUnits;
    }

    public int getFloor() {
        return floor;
    }

    public int getDistanceUnits() {
        return distanceUnits;
    }

    /**
     * Calculates a weighted distance. Changing floors is heavily penalized.
     */
    public static int calculateDistance(Location loc1, Location loc2) {
        int floorDistance = Math.abs(loc1.getFloor() - loc2.getFloor());
        int unitDistance = Math.abs(loc1.getDistanceUnits() - loc2.getDistanceUnits());

        // Penalize changing floors by a large factor (e.g., 100 units per floor)
        return (floorDistance * 100) + unitDistance;
    }
}

