package com.gamedesign.game;

import com.gamedesign.game.jump.Jump;
import com.gamedesign.game.jump.Ladder;
import com.gamedesign.game.jump.Snake;

import java.util.List;

public class Board {
    private final int size;
    private final Cell[][] cells;

    public Board(int size, List<Snake> snakes, List<Ladder> ladders) {
        this.size = size;
        this.cells = new Cell[size][size];
        initializeCells();
        addJumps(snakes, ladders);
    }

    private void initializeCells() {
        for (int i = 0; i < size; i++) {
            for (int j = 0; j < size; j++) {
                int position = (i * size) + j + 1;
                cells[i][j] = new Cell(position);
            }
        }
    }

    private void addJumps(List<Snake> snakes, List<Ladder> ladders) {
        for (Snake snake : snakes) {
            addJumpToCell(snake);
        }
        for (Ladder ladder : ladders) {
            addJumpToCell(ladder);
        }
    }

    private void addJumpToCell(Jump jump) {
        int startPosition = jump.getStart();
        // Assuming position starts from 1
        int row = (startPosition - 1) / size;
        int col = (startPosition - 1) % size;
        cells[row][col].setJump(jump);
    }

    public Cell getCell(int position) {
        if (position < 1 || position > size * size) {
            return null; // Or throw an exception
        }
        int row = (position - 1) / size;
        int col = (position - 1) % size;
        return cells[row][col];
    }

    public int getSize() {
        return size;
    }
}

